  ('social-worker-moex-01851', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'essay', '近年來數位科技與社群媒體開始應用於社工實務中，社工員在運用這些工具於福利
服務時，應留意那些倫理議題？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01852', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「對於助人的專業關係並不重視，認為工作者與案主的關係是專家對案主的關係，工作者必須保持客觀、 控制自己的情緒來幫助案主，使其可以頓悟及解決內心衝突」，以上敘述是屬於下列那種社會工作實施 理論的觀點？', '["功能學派", "問題解決學派", "行為修正學派", "診斷學派"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01853', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於自我表露（self-disclosure），下列敘述何者錯誤？', '["自我表露指的是社工者透過口語及非口語的方式，有意且有目的的透露自己的相關訊息給案主知道", "自我表露的類型可分為立即性（immediacy）以及個人性的自我表露（personal self-disclosure）", "自我表露要以誠實為基礎來運作，不論是否會威脅到專業關係", "自我表露會提出與案主互動過程中對於案主的看法，帶有分享與面質的意味"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01854', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '面對倫理兩難的困境，Lowenberg和Dolgoff（1992）將①自決自主原則、②生命品質原則、③保護案主', '["平等待遇原則、⑤最小傷害原則、⑥真誠原則以及⑦隱私保密原則等七大項倫理規範排出 優先順序，以下何者正確？", "", "", "⑤"]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01855', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於個案管理（case management）與社會個案工作的比較，以下何者錯誤？', '["個案管理更注重人與環境，必要時會將環境因素納入處遇策略", "個案管理者通常被期待成為通才，而非專家角色", "個案管理更重視資源的連結與運用", "個案管理對問題的解決大多採直接服務的方式，特別是以任務導向的短期處遇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01856', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在接案會談（intake interview）中，下列何者非社會工作者該做的事？', '["對於案主的問題儘可能地深入探詢與瞭解", "與案主建立信賴的關係", "若非機構職掌範圍則可協助轉介", "介紹機構的功能與服務進行的方式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01857', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於會談中「面質」（confronting）技巧的運用，以下敘述何者錯誤？', '["要在已和案主有良好關係後才使用", "面質前後使用同理心技巧有助面質成功", "可能會造成與案主的對立，因此應避免使用", "使用時機為當案主在會談過程中表現出不一致或過度防衛行為時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01858', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於案主的自我決定（self-determination），以下敘述何者錯誤？', '["案主自我決定是基於案主的能力做積極建設的決定", "自我決定是社會個案工作的價值，無論如何均要予以尊重", "為了讓案主能自我決定，工作者需引導案主看清自己的問題和需要所在，瞭解有那些資源可運用，引 發案主的分辨力", "營造能使案主成長，解決自己問題的信賴關係的工作環境很重要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01859', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依團體目的（purpose），可將組成團體（formed groups）分為治療性團體（treatment group）以及任務性 團體（task group）。以下何者屬任務性團體的類型？', '["跨專業的治療會議", "安養機構的住民會議", "唐氏症兒童的家長團體", "病患適應團體"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01860', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '系統理論嘗試將團體視為互動元素的一個體系。根據Parsons、Bales 及Shils（1953）的觀點，團體體系 必須要完成四個主要功能性的任務，並維持平衡狀態。下列何者非其任務？', '["整合（integration）", "應用（application）", "適應（adaptation）", "目標達成（goal attainment）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
